const e=JSON.parse('{"key":"v-c98ebba2","path":"/learningNote/TypeScriptNote/%E7%AC%AC%E5%9B%9B%E5%A4%A9.html","title":"TypeScript第四天 面向对象（上）","lang":"zh-CN","frontmatter":{"title":"TypeScript第四天 面向对象（上）","icon":"typescript","date":"2022-09-13T00:00:00.000Z","category":["TypeScript","Web"]},"headers":[{"level":2,"title":"简述","slug":"简述","link":"#简述","children":[]},{"level":2,"title":"1、类（class）与对象","slug":"_1、类-class-与对象","link":"#_1、类-class-与对象","children":[]},{"level":2,"title":"2、面向对象的特点","slug":"_2、面向对象的特点","link":"#_2、面向对象的特点","children":[{"level":3,"title":"2.1 封装 （重要！）","slug":"_2-1-封装-重要","link":"#_2-1-封装-重要","children":[]},{"level":3,"title":"2.2 继承","slug":"_2-2-继承","link":"#_2-2-继承","children":[]}]}],"git":{"createdTime":1692892792000,"updatedTime":1693300529000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":3}]},"readingTime":{"minutes":6.72,"words":2017},"filePathRelative":"learningNote/TypeScriptNote/第四天.md","localizedDate":"2022年9月13日","excerpt":"<h2> 简述</h2>\\n<p>面向对象是程序中一个非常重要的思想，面向对象很简单，简而言之就是：程序之中所有的操作都需要通过对象来完成。</p>\\n<ul>\\n<li>举例而言：\\n<ul>\\n<li>操作浏览器要使用window对象</li>\\n<li>操作网页要使用document对象</li>\\n<li>操作控制台要使用console对象</li>\\n</ul>\\n</li>\\n</ul>\\n<p>一切操作都要通过对象，这就是所谓的面向对象，那么对象到底是什么呢？这就要先说到程序是什么，计算机程序的本质就是对现实事物的抽象，抽象的反义词是具体，比如：照片是对一个具体的人的抽象，汽车模型是对具体汽车的抽象等等。程序也是对事物的抽象，一个事物到了程序中就变成了一个对象。</p>"}');export{e as data};
